    /**
     * Get all of SECCFG's bit fields.
     *
     * (read-write) Security configuration for channel 0. Control whether this
     * channel performs Secure/Non-secure and Privileged/Unprivileged bus
     * accesses.
     *
     *                     If this channel generates bus accesses of some
     * security level, an access of at least that level (in the order S+P > S+U
     * > NS+P > NS+U) is required to program, trigger, abort, check the status
     * of, interrupt on or acknowledge the interrupt of this channel.
     *
     *                     This register automatically locks down (becomes
     * read-only) once software starts to configure the channel.
     *
     *                     This register is world-readable, but is writable
     * only from a Secure, Privileged context.
     */
    inline void get_SECCFG(std::size_t index, bool &P, bool &S,
                           bool &LOCK) volatile
    {
        uint32_t curr = SECCFG[index];

        P = curr & 1u;
        S = curr & (1u << 1u);
        LOCK = curr & (1u << 2u);
    }

    /**
     * Set all of SECCFG's bit fields.
     *
     * (read-write) Security configuration for channel 0. Control whether this
     * channel performs Secure/Non-secure and Privileged/Unprivileged bus
     * accesses.
     *
     *                     If this channel generates bus accesses of some
     * security level, an access of at least that level (in the order S+P > S+U
     * > NS+P > NS+U) is required to program, trigger, abort, check the status
     * of, interrupt on or acknowledge the interrupt of this channel.
     *
     *                     This register automatically locks down (becomes
     * read-only) once software starts to configure the channel.
     *
     *                     This register is world-readable, but is writable
     * only from a Secure, Privileged context.
     */
    inline void set_SECCFG(std::size_t index, bool P, bool S,
                           bool LOCK) volatile
    {
        uint32_t curr = SECCFG[index];

        curr &= ~(0b1u);
        curr |= (P & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (S & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (LOCK & 0b1u) << 2u;

        SECCFG[index] = curr;
    }

