        TIMER0_S = curr & (1u << 3u);
        TIMER1_P = curr & (1u << 4u);
        TIMER1_S = curr & (1u << 5u);
        TIMER2_P = curr & (1u << 6u);
        TIMER2_S = curr & (1u << 7u);
        TIMER3_P = curr & (1u << 8u);
        TIMER3_S = curr & (1u << 9u);
