        curr &= ~(0b1u << 2u);
        curr |= (TIMER0_P & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (TIMER0_S & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (TIMER1_P & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (TIMER1_S & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (TIMER2_P & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (TIMER2_S & 0b1u) << 7u;
        curr &= ~(0b1u << 8u);
        curr |= (TIMER3_P & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (TIMER3_S & 0b1u) << 9u;

        SECCFG_MISC = curr;
